package com.bankapp.module;

import android.content.Context;
import android.os.AsyncTask;
import android.util.Log;
import java.math.BigDecimal;
import java.math.RoundingMode;
import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

public class BankingModule {
    private static final String TAG = "BankingModule";
    private Context context;
    private List<Account> accounts;
    private ExecutorService executorService;
    
    public BankingModule(Context context) {
        this.context = context;
        this.accounts = new ArrayList<>();
        this.executorService = Executors.newFixedThreadPool(2);
        initializeDefaultAccounts();
    }
    
    private void initializeDefaultAccounts() {
        accounts.add(new Account("ACC001", "Checking", new BigDecimal("1500.00")));
        accounts.add(new Account("ACC002", "Savings", new BigDecimal("5000.00")));
        accounts.add(new Account("ACC003", "Credit", new BigDecimal("-200.00")));
    }
    
    public void processTransaction(Transaction transaction, TransactionCallback callback) {
        executorService.execute(() -> {
            try {
                if (validateTransaction(transaction)) {
                    Account account = getAccountById(transaction.getAccountId());
                    if (account != null) {
                        BigDecimal newBalance = calculateNewBalance(account, transaction);
                        if (newBalance != null && newBalance.compareTo(BigDecimal.ZERO) >= 0 || 
                            (account.getAccountType().equals("Credit") && 
                             newBalance.compareTo(account.getBalance()) <= 0)) {
                            
                            account.setBalance(newBalance);
                            transaction.setStatus("SUCCESS");
                            transaction.setTimestamp(System.currentTimeMillis());
                            
                            if (callback != null) {
                                callback.onSuccess(transaction);
                            }
                        } else {
                            transaction.setStatus("INSUFFICIENT_FUNDS");
                            if (callback != null) {
                                callback.onError("Insufficient funds");
                            }
                        }
                    } else {
                        transaction.setStatus("ACCOUNT_NOT_FOUND");
                        if (callback != null) {
                            callback.onError("Account not found");
                        }
                    }
                } else {
                    transaction.setStatus("VALIDATION_FAILED");
                    if (callback != null) {
                        callback.onError("Transaction validation failed");
                    }
                }
            } catch (Exception e) {
                Log.e(TAG, "Transaction processing error", e);
                transaction.setStatus("ERROR");
                if (callback != null) {
                    callback.onError("Processing error: " + e.getMessage());
                }
            }
        });
    }
    
    private boolean validateTransaction(Transaction transaction) {
        return transaction.getAccountId() != null && 
               transaction.getAmount() != null && 
               transaction.getAmount().compareTo(BigDecimal.ZERO) > 0 &&
               transaction.getTransactionType() != null;
    }
    
    private BigDecimal calculateNewBalance(Account account, Transaction transaction) {
        BigDecimal amount = transaction.getAmount();
        if (account.getAccountType().equals("Credit")) {
            if (transaction.getTransactionType().equals("DEBIT")) {
                return account.getBalance().add(amount);
            } else if (transaction.getTransactionType().equals("CREDIT")) {
                return account.getBalance().subtract(amount);
            }
        } else {
            if (transaction.getTransactionType().equals("DEBIT")) {
                return account.getBalance().subtract(amount);
            } else if (transaction.getTransactionType().equals("CREDIT")) {
                return account.getBalance().add(amount);
            }
        }
        return null;
    }
    
    public Account getAccountById(String accountId) {
        for (Account account : accounts) {
            if (account.getAccountId().equals(accountId)) {
                return account;
            }
        }
        return null;
    }
    
    public List<Account> getAllAccounts() {
        return new ArrayList<>(accounts);
    }
    
    public BigDecimal getAccountBalance(String accountId) {
        Account account = getAccountById(accountId);
        return account != null ? account.getBalance() : BigDecimal.ZERO;
    }
    
    public void updateAccountBalance(String accountId, BigDecimal newBalance) {
        Account account = getAccountById(accountId);
        if (account != null) {
            account.setBalance(newBalance);
        }
    }
    
    public void shutdown() {
        if (executorService != null && !executorService.isShutdown()) {
            executorService.shutdown();
        }
    }
    
    public interface TransactionCallback {
        void onSuccess(Transaction transaction);
        void onError(String error);
    }
    
    public static class Account {
        private String accountId;
        private String accountType;
        private BigDecimal balance;
        
        public Account(String accountId, String accountType, BigDecimal balance) {
            this.accountId = accountId;
            this.accountType = accountType;
            this.balance = balance;
        }
        
        public String getAccountId() {
            return accountId;
        }
        
        public String getAccountType() {
            return accountType;
        }
        
        public BigDecimal getBalance() {
            return balance;
        }
        
        public void setBalance(BigDecimal balance) {
            this.balance = balance.setScale(2, RoundingMode.HALF_UP);
        }
    }
    
    public static class Transaction {
        private String accountId;
        private String transactionType;
        private BigDecimal amount;
        private String status;
        private long timestamp;
        private String description;
        
        public Transaction(String accountId, String transactionType, BigDecimal amount) {
            this.accountId = accountId;
            this.transactionType = transactionType;
            this.amount = amount;
        }
        
        public String getAccountId() {
            return accountId;
        }
        
        public String getTransactionType() {
            return transactionType;
        }
        
        public BigDecimal getAmount() {
            return amount;
        }
        
        public String getStatus() {
            return status;
        }
        
        public void setStatus(String status) {
            this.status = status;
        }
        
        public long getTimestamp() {
            return timestamp;
        }
        
        public void setTimestamp(long timestamp) {
            this.timestamp = timestamp;
        }
        
        public String getDescription() {
            return description;
        }
        
        public void setDescription(String description) {
            this.description = description;
        }
    }
}